233			.din_a_i(shift_1_dout_i),//fb
234			.din_b_r(radix_no4_op_r),//input
235			.din_b_i(radix_no4_op_i),//input
236			.w_r(24'd256),//twindle
237			.w_i(24'd0),//d
238			.op_r(out_r),
239			.op_i(out_i),
240			.delay_r(radix_no5_delay_r),
241			.delay_i(radix_no5_delay_i),
242			.outvalid()
243		);
244	
245	shift_1 shift_1(
246			.clk(clk),.reset(reset),
247			.in_valid(radix_no4_outvalid),
248			.din_r(radix_no5_delay_r),
249			.din_i(radix_no5_delay_i),
250			.dout_r(shift_1_dout_r),
251			.dout_i(shift_1_dout_i)
252		);
253	
254		always@(posedge clk or posedge reset)begin
255			if(reset)begin
256				din_r_reg <= 0;
257				din_i_reg <= 0;
258				in_valid_reg <= 0;
259				s5_count <= 0;
260				r4_valid <= 0;
261				count_y <= 0;
262				assign_out <= 0;
263				over <= 0;
264				dout_r <= 0;
265				dout_i <= 0;
266				y_1_delay <= 0;
267				for (i=0;i<=31;i=i+1) begin
268					result_r[i] <= 0;
269					result_i[i] <= 0;
270				end
271			end
272			else begin
273				din_r_reg <= {{4{din_r[11]}},din_r,8'b0};
274				din_i_reg <= {{4{din_i[11]}},din_i,8'b0};
275				in_valid_reg <= in_valid;
276				s5_count <= next_s5_count;
277				r4_valid <= next_r4_valid;
278				count_y  <= next_count_y;
279				assign_out <= next_out_valid;
280				over <= next_over;
281				y_1_delay <= y_1;
282				dout_r <= next_dout_r;
283				dout_i <= next_dout_i;
284				for (i=0;i<=31;i=i+1) begin
285					result_r[i] <= result_r_ns[i];
286					result_i[i] <= result_i_ns[i];
287				end
288			end
289		end
290		always@(*)begin
291	
292			next_r4_valid = radix_no4_outvalid;
293			if (r4_valid)next_s5_count = s5_count + 1;
294			else next_s5_count = s5_count;
295			
296			if(r4_valid && s5_count == 1'b0)no5_state = 2'b01;
297			else if(r4_valid && s5_count == 1'b1)no5_state = 2'b10;
298			else no5_state = 2'b00;
299	
300			if(radix_no4_outvalid) next_count_y = count_y + 5'd1;
301			else next_count_y = count_y;
302	
303			if(next_out_valid) begin
304				next_dout_r = result_r[y_1_delay];
305				next_dout_i = result_i[y_1_delay];
306			end
307			else begin
308				next_dout_r = dout_r;
309				next_dout_i = dout_i;
310			end
311		end
312		
313		always @(*) begin
314	
315			next_over = over;
316			for (i=0;i<=31;i=i+1) begin
317				result_r_ns[i] = result_r[i];
318				result_i_ns[i] = result_i[i];
319			end
320			if(next_over==1'b1)next_out_valid = 1'b1;
321			else next_out_valid = assign_out;
322	
323			if(over!=1'b1) begin
324				case((y_1))
325				5'd0 : begin            
326					result_r_ns[31] = out_r[23:8];
327					result_i_ns[31] = out_i[23:8];
328					
329				end
330				5'd1 : begin            
331					result_r_ns[15] = out_r[23:8];
332					result_i_ns[15] = out_i[23:8];
333				end
334				5'd2 : begin            
335					result_r_ns[7 ] = out_r[23:8];
336					result_i_ns[7 ] = out_i[23:8];
337				end
338				5'd3 : begin            
339					result_r_ns[23] = out_r[23:8];
340					result_i_ns[23] = out_i[23:8];
341				end
342				5'd4 : begin            
343					result_r_ns[3 ] = out_r[23:8];
344					result_i_ns[3 ] = out_i[23:8];
345				end
346				5'd5 : begin            
347					result_r_ns[19] = out_r[23:8];
348					result_i_ns[19] = out_i[23:8];
349				end
350				5'd6 : begin            
351					result_r_ns[11] = out_r[23:8];
352					result_i_ns[11] = out_i[23:8];
353				end
354				5'd7 : begin            
355					result_r_ns[27] = out_r[23:8];
356					result_i_ns[27] = out_i[23:8];
357				end
358				5'd8: begin            
359					result_r_ns[1 ] = out_r[23:8];
360					result_i_ns[1 ] = out_i[23:8];
361				end
362				5'd9: begin            
363					result_r_ns[17] = out_r[23:8];
364					result_i_ns[17] = out_i[23:8];
365				end
366				5'd10: begin            
367					result_r_ns[9] = out_r[23:8];
368					result_i_ns[9] = out_i[23:8];
369				end
370				5'd11: begin            
371					result_r_ns[25] = out_r[23:8];
372					result_i_ns[25] = out_i[23:8];
373				end
374				5'd12: begin            
375					result_r_ns[5 ] = out_r[23:8];
376					result_i_ns[5 ] = out_i[23:8];
377				end
378				5'd13: begin            
379					result_r_ns[21] = out_r[23:8];
380					result_i_ns[21] = out_i[23:8];
381				end
382				5'd14: begin            
383					result_r_ns[13] = out_r[23:8];
384					result_i_ns[13] = out_i[23:8];
385				end
386				5'd15: begin            
387					result_r_ns[29] = out_r[23:8];
388					result_i_ns[29] = out_i[23:8];
389				end
390				5'd16: begin            
391					result_r_ns[0 ] = out_r[23:8];
392					result_i_ns[0 ] = out_i[23:8];
393				end
394				5'd17: begin            
395					result_r_ns[16] = out_r[23:8];
396					result_i_ns[16] = out_i[23:8];
397				end
398				5'd18: begin            
399					result_r_ns[8 ] = out_r[23:8];
400					result_i_ns[8 ] = out_i[23:8];
401				end
402				5'd19: begin            
403					result_r_ns[24] = out_r[23:8];
404					result_i_ns[24] = out_i[23:8];
405				end
406				5'd20: begin            
407					result_r_ns[4 ] = out_r[23:8];
408					result_i_ns[4 ] = out_i[23:8];
409				end
410				5'd21: begin            
411					result_r_ns[20] = out_r[23:8];
412					result_i_ns[20] = out_i[23:8];
413				end
414				5'd22: begin            
415					result_r_ns[12] = out_r[23:8];
416					result_i_ns[12] = out_i[23:8];
417				end
418				5'd23: begin            
419					result_r_ns[28] = out_r[23:8];
420					result_i_ns[28] = out_i[23:8];
421				end
422				5'd24: begin            
423					result_r_ns[2 ] = out_r[23:8];
424					result_i_ns[2 ] = out_i[23:8];
425				end
426				5'd25: begin            
427					result_r_ns[18] = out_r[23:8];
428					result_i_ns[18] = out_i[23:8];
429				end
430				5'd26: begin            
431					result_r_ns[10] = out_r[23:8];
432					result_i_ns[10] = out_i[23:8];
433				end
434				5'd27: begin            
435					result_r_ns[26] = out_r[23:8];
436					result_i_ns[26] = out_i[23:8];
437				end
438				5'd28: begin            
439					result_r_ns[6 ] = out_r[23:8];
440					result_i_ns[6 ] = out_i[23:8];
441				end
442				5'd29: begin            
443					result_r_ns[22] = out_r[23:8];
444					result_i_ns[22] = out_i[23:8];
445				end
446				5'd30 : begin            
447					result_r_ns[14] = out_r[23:8];
448					result_i_ns[14] = out_i[23:8];
449				end
450				5'd31 : begin            
